class Solution:
    def smallestUniqueSubarray(self, nums):
        n = len(nums)
        for length in range(1, n + 1):
            counts = {}
            for start in range(n - length + 1):
                key = tuple(nums[start:start + length])
                counts[key] = counts.get(key, 0) + 1
            if any(c == 1 for c in counts.values()):
                return length
        return n

