class Solution:
    def smallestUniqueSubarray(self, nums):
        n = len(nums)
        MOD1 = 1_000_000_007
        MOD2 = 998_244_353
        BASE1 = 131
        BASE2 = 137

        pow1 = [1] * (n + 1)
        pow2 = [1] * (n + 1)
        for i in range(1, n + 1):
            pow1[i] = pow1[i - 1] * BASE1 % MOD1
            pow2[i] = pow2[i - 1] * BASE2 % MOD2

        prefix1 = [0] * (n + 1)
        prefix2 = [0] * (n + 1)
        for i in range(n):
            v = nums[i] + 1
            prefix1[i + 1] = (prefix1[i] * BASE1 + v) % MOD1
            prefix2[i + 1] = (prefix2[i] * BASE2 + v) % MOD2

        def get_hash(l, length):
            r = l + length
            h1 = (prefix1[r] - prefix1[l] * pow1[length]) % MOD1
            h2 = (prefix2[r] - prefix2[l] * pow2[length]) % MOD2
            return (h1, h2)

        def has_unique(length):
            seen = {}
            for start in range(n - length + 1):
                h = get_hash(start, length)
                seen[h] = seen.get(h, 0) + 1
            return any(c == 1 for c in seen.values())

        lo, hi = 1, n
        while lo < hi:
            mid = (lo + hi) // 2
            if has_unique(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

