var smallestUniqueSubarray = function(nums) {
    const n = nums.length;
    const MOD1 = 1000000007;
    const MOD2 = 998244353;
    const BASE1 = 131;
    const BASE2 = 137;

    const pow1 = new Array(n + 1).fill(1);
    const pow2 = new Array(n + 1).fill(1);
    for (let i = 1; i <= n; i++) {
        pow1[i] = (pow1[i - 1] * BASE1) % MOD1;
        pow2[i] = (pow2[i - 1] * BASE2) % MOD2;
    }

    const prefix1 = new Array(n + 1).fill(0);
    const prefix2 = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        const v = nums[i] + 1;
        prefix1[i + 1] = (prefix1[i] * BASE1 + v) % MOD1;
        prefix2[i + 1] = (prefix2[i] * BASE2 + v) % MOD2;
    }

    function mulmod(a, b, mod) {
        return Number((BigInt(a) * BigInt(b)) % BigInt(mod));
    }

    function getHash(l, length) {
        const r = l + length;
        let h1 = (prefix1[r] - mulmod(prefix1[l], pow1[length], MOD1)) % MOD1;
        let h2 = (prefix2[r] - mulmod(prefix2[l], pow2[length], MOD2)) % MOD2;
        if (h1 < 0) h1 += MOD1;
        if (h2 < 0) h2 += MOD2;
        return h1 + "_" + h2;
    }

    function hasUnique(length) {
        const seen = new Map();
        for (let start = 0; start <= n - length; start++) {
            const h = getHash(start, length);
            seen.set(h, (seen.get(h) || 0) + 1);
        }
        for (const c of seen.values()) {
            if (c === 1) return true;
        }
        return false;
    }

    let lo = 1, hi = n;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (hasUnique(mid)) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
